215	func detectedFromQuota(q *ProviderQuota) *detectedRow {
216		if q == nil {
217			return nil
218		}
219		row := &detectedRow{ceilingTokens: -1, remaining: -1}
220		if q.CeilingTokens != nil {
221			row.ceilingTokens = *q.CeilingTokens
222		}
223		if q.Remaining != nil {
224			row.remaining = *q.Remaining
225		}
226		return row
227	}
