229	// projectRunOutHours returns the hours projected until current headroom is used
230	// based on the last-24-hour slope of the bucket series. Returns 0 when the
231	// slope is non-positive, headroom is gone/unknown, or the series is too
232	// short to estimate.
233	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
234		if len(buckets) < 2 {
235			return 0
236		}
237		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
238		// buckets; 1h buckets gives 24.
239		n := 24
240		if n > len(buckets) {
241			n = len(buckets)
242		}
243		tail := buckets[len(buckets)-n:]
244		tokens := make([]float64, len(tail))
245		for i, b := range tail {
246			tokens[i] = float64(b.Tokens)
247		}
248		perBucket := agent.LinearSlope(tokens)
249		// Convert slope-per-bucket to slope-per-hour.
250		var bucketHours float64
251		if len(tail) >= 2 {
252			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
253		}
254		if bucketHours <= 0 {
255			bucketHours = 1
256		}
257		perHour := perBucket / bucketHours
258		if perHour <= 0 {
259			return 0
260		}

